import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { phongAPI } from '../services/api';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

export default function ChiTietPhong() {
  const { id } = useParams();
  const [phong, setPhong] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    phongAPI.layChiTiet(id)
      .then(r => setPhong(r.data.data))
      .catch(() => toast.error('Không tìm thấy phòng'))
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="spinner" />;
  if (!phong) return <div className="container page-wrapper"><div className="alert alert-danger">Không tìm thấy phòng.</div></div>;

  return (
    <div className="container page-wrapper">
      <div className="grid-2" style={{ alignItems:'start' }}>
        <div className="card">
          <div className="card-body">
            <h1 style={{ fontSize: 26, fontWeight: 800 }}>{phong.title}</h1>
            <div style={{ fontSize: 28, fontWeight: 800, color:'var(--primary)', margin:'10px 0' }}>{fmt(phong.giaTien)}/tháng</div>
            <div style={{ color:'var(--text-muted)', marginBottom: 16 }}>📍 {phong.diaChi}</div>
            <div style={{ display:'flex', gap: 20, marginBottom: 20 }}>
              <div className="stat-card" style={{ flex:1, padding: 16 }}>
                <div className="stat-value">{phong.soNguoiHienTai}</div>
                <div className="stat-label">Hiện tại</div>
              </div>
              <div className="stat-card" style={{ flex:1, padding: 16 }}>
                <div className="stat-value">{phong.soNguoiToiDa}</div>
                <div className="stat-label">Tối đa</div>
              </div>
              <div className="stat-card" style={{ flex:1, padding: 16 }}>
                <div className="stat-value">{phong.soNguoiToiDa - phong.soNguoiHienTai}</div>
                <div className="stat-label">Còn chỗ</div>
              </div>
            </div>
            {phong.moTa && <p style={{ color:'var(--text-muted)', lineHeight: 1.8 }}>{phong.moTa}</p>}
          </div>
        </div>

        <div className="card">
          <div className="card-header">👥 Thành viên hiện tại</div>
          <div className="card-body">
            <div style={{ display:'flex', alignItems:'center', gap: 12, padding:'12px 0', borderBottom:'1px solid var(--border)' }}>
              <img src={phong.avatarChuPhong || `https://ui-avatars.com/api/?name=${encodeURIComponent(phong.tenChuPhong)}&background=12355B&color=fff&size=40`}
                className="avatar avatar-sm" alt="" />
              <div>
                <div style={{ fontWeight: 700 }}>{phong.tenChuPhong}</div>
                <span className="badge badge-info">Chủ phòng</span>
              </div>
            </div>
            {phong.danhSachThanhVien?.map(m => (
              <div key={m.maNguoiDung} style={{ display:'flex', alignItems:'center', gap: 12, padding:'12px 0', borderBottom:'1px solid var(--border)' }}>
                <img src={m.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(m.hoTen)}&size=40`}
                  className="avatar avatar-sm" alt="" />
                <div style={{ fontWeight: 600 }}>{m.hoTen}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
